// modules/billing/routes/loader.ts
import { defineLoader } from 'aether';
import { requireUser, getSession } from '/lib/auth';
import { Result, ok, err } from '/lib/result';
import { query } from '/lib/db';
import { User, BillingSummary } from '/lib/types';

export default defineLoader({
  name: 'billing-summary',
  description: 'Returns a billing summary for the current user.',
  auth: true,
  cache: {
    ttl: 60, // Cache for 60 seconds
  },
  async handler(req) {
    const user = await requireUser(req);
    if (!user) return err('Unauthorized');

    const session = await getSession(req);
    if (!session) return err('Session not found');

    try {
      const result: Result<BillingSummary, Error> = await query<BillingSummary>(
        `
          SELECT
            current_plan,
            next_invoice_date,
            lifetime_spend,
            outstanding_credit
          FROM billing_summary
          WHERE user_id = $1;
        `,
        [user.id]
      );

      if (result.isErr()) return err(result.error);

      return ok(result.value);
    } catch (error) {
      return err(error as Error);
    }
  },
});

